const body = $input.first().json.body;
if (!body.business_name || !body.email || !body.primary_region) {
  return [{json: {success: false, error: "Missing required fields"}}];
}
const clientId = body.business_name.replace(/[^a-zA-Z0-9]/g, "-").replace(/-+/g, "-").replace(/^-|-$/g, "").toUpperCase();
const locations = [body.primary_region];
if (body.locations) {
  const additional = Array.isArray(body.locations) ? body.locations : [body.locations];
  additional.forEach(loc => { if (!locations.includes(loc)) locations.push(loc); });
}
const compliance = body.compliance || ["SOC2"];

const payload = {
  client_id: clientId,
  business_name: body.business_name,
  customer_email: body.email,
  stripe_session_id: body.stripe_session_id || "",
  stripe_subscription_id: body.stripe_subscription_id || "",
  billing_period: body.billing_period || "monthly",
  tier: "enterprise",
  compliance: (Array.isArray(compliance) ? compliance : [compliance]).join(","),
  locations: locations.join(","),
  primary_region: body.primary_region,
  industry: body.industry || "general",
  brand_color: body.brand_color || "#001a2d"
};

return [{json: {
  success: true,
  message: "Configuration received.",
  client_id: clientId,
  payload: payload
}}];
